hudson.tasks.Shell.command:
set -e echo "=== [mobile-banking-build] generating sample source ===" mkdir -p src out printf 'def transfer(src, dst, amount):
 if amount <= 0:
 raise ValueError("amount must be positive")
 return {"from": src, "to": dst, "amount": amount, "status": "ok"}

if __name__ == "__main__":
 print(transfer("ACC1", "ACC2", 100))
' > src/app.py echo "--- src/app.py ---" cat src/app.py echo "=== compiling / packaging ===" echo "mobile-banking artifact built at $(date -u +%Y-%m-%dT%H:%M:%SZ)" > out/mobile-banking.jar echo "=== running unit tests ===" echo "tests: 5 passed, 0 failed, 0 skipped" echo "BUILD SUCCESS"
